function patchLoad(){const app=window.DOIT_JSON_APP;if(!app||app.__psFullSourceFix303)return false;const old=app.load.bind(app);app.load=(payload,m={})=>{const arr=payload?.rows||payload;if(Array.isArray(arr)){const set=new Set(arr.map(r=>cleanPs(r.ps)).filter(Boolean));const next=[...set].sort((a,b)=>a.localeCompare(b,'th'));if(next.length>=allPsOptions.length)allPsOptions=next}pruneSelected();publishPsScope();return old(payload,m)};app.__psFullSourceFix303=true;return true}
