function syncPsBtn(){pruneSelected();publishPsScope();const b=$('#psTickBtn289'),list=selectedList();if(!b)return;b.textContent=list.length?`PS: ${list.length===1?list[0]:list.length+' คน'} ▼`:'PS: ทั้งหมด ▼'}
function installPsTickButton(){const el=$('#psSelect');if(!el)return;const field=el.closest('.field');if(!field)return;if(!$('#psTickBtn289')){const b=document.createElement('button');b.type='button';b.id='psTickBtn289';b.className='psTickBtn289';b.onclick=openPs;field.insertBefore(b,el)}hideLegacyPsSelect();syncPsBtn();if(!el.dataset.psTick303){el.dataset.psTick303='1';el.addEventListener('change',()=>{cleanSelect();hideLegacyPsSelect();const v=cleanPs(el.value);if(v&&!selectedPs.has(v)&&selectedPs.size<=1){selectedPs=new Set([v])}pruneSelected();syncPsBtn()})}}
function boot(){patchLoad();cleanSelect();forceCenteredDate();installPsTickButton();collectFullPs();pruneSelected();publishPsScope();let n=0;const tick=()=>{patchLoad();cleanSelect();forceCenteredDate();installPsTickButton();collectFullPs();pruneSelected();publishPsScope();syncPsBtn();if(++n<40)setTimeout(tick,300)};setTimeout(tick,300)}
